import React from 'react';
import './AboutMe.css';
import Headshot from '../assets/headshotzoomed.png'; 

const AboutMe = () => {
  return (
    <div className='mycookbook'>
        <h2 className='header2'>ABOUT ME</h2>
        <div className="content-container"> {/* Flex container */}
            <div className="image-container">
                <img src={Headshot} alt="Profile" />
            </div>
            <div className="text-container"> 
                <p className='heading3'>Education</p>
                <span className='bar'></span>
                <p> I'm a second year student at Northwestern University pursuing a B.S. in Computer Science and minor in Philosophy on the Pre-Law track with an interest in natural language processing, information ethics, and data privacy. I'm also interested in research within the intersection of AI & Law, as well as tech law and intellectual property/patent law. </p>
                <p> shraeya.iyer@u.northwestern.edu </p>
            </div>
        </div>
    </div>
  );
};

export default AboutMe;
